#include <stdio.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[100001];
        scanf("%s", S);
        long long node = 1;
        for (int i = 0; S[i]; i++) {
            if (S[i] == 'l') {
                node = (node * 2) % MOD;
            } else {
                node = (node * 2 + 1) % MOD;
            }
        }
        printf("%lld\n", node);
    }
    return 0;
}

