        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            long node = 1;
            for (char c : S.toCharArray()) {
                if (c == 'l') {
                    node = (node * 2) % 1000000007;
                } else {
                    node = (node * 2 + 1) % 1000000007;
                }
            }
            System.out.println(node);
        }
    }
}

